    /**
     * @method
     * @name bitstamp#fetchMarkets
     * @description retrieves data on all markets for bitstamp
     * @see https://www.bitstamp.net/api/#tag/Market-info/operation/GetTradingPairsInfo
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.fetchMarketsFromCache(parameters)).join();
            //
            //    [
            //
            //   spot:
            //
            //        {
            //            "name": "BTC/USD",
            //            "market_symbol": "btcusd",
            //            "base_currency": "BTC",
            //            "base_decimals": 8,
            //            "counter_currency": "USD",
            //            "counter_decimals": 0,
            //            "minimum_order_value": "10",
            //            "trading": "Enabled",
            //            "instant_order_counter_decimals": 2,
            //            "instant_and_market_orders": "Enabled",
            //            "description": "Bitcoin / U.S. dollar",
            //            "market_type": "SPOT"
            //        },
            //        ...
            //
            //    perp:
            //
            //         {
            //             "name": "BTC/USD-PERP",
            //             "market_symbol": "btcusd-perp",
            //             "base_currency": "BTC",
            //             "base_decimals": 5,
            //             "counter_currency": "USD",
            //             "counter_decimals": 0,
            //             "minimum_order_value": "10",
            //             "maximum_order_value": "500000.00000000",
            //             "minimum_order_amount": "0.00001000",
            //             "maximum_order_amount": "10.00000000",
            //             "trading": "Enabled",
            //             "instant_order_counter_decimals": 2,
            //             "instant_and_market_orders": "Enabled",
            //             "description": "Bitcoin / U.S. dollar Perpetual",
            //             "market_type": "PERPETUAL",
            //             "underlying_asset": "Kaiko BTC Benchmark Reference Rate",
            //             "payoff_type": "Linear",
            //             "contract_size": "1.00000000",
            //             "isin": "EZHKD4DNKHY3"
            //         }
            //
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
            {
                Object market = Helpers.GetValue(response, i);
                var baseIdquoteIdVariable = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeString(market, "base_currency"), this.safeString(market, "counter_currency")));
                var baseId = ((java.util.List<Object>) baseIdquoteIdVariable).get(0);
                var quoteId = ((java.util.List<Object>) baseIdquoteIdVariable).get(1);
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
                Object settleId = null;
                Object marketTypeRaw = this.safeString(market, "market_type");
                Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
                Object type = null;
                Object subType = null;
                if (Helpers.isTrue(Helpers.isEqual(marketTypeRaw, "SPOT")))
                {
                    type = "spot";
                } else if (Helpers.isTrue(Helpers.isEqual(marketTypeRaw, "PERPETUAL")))
                {
                    type = "swap";
                    settleId = quoteId;
                    symbol = Helpers.add(Helpers.add(Helpers.add(Helpers.add(base, "/"), quote), ":"), settleId);
                    Object payoffType = this.safeString(market, "payoff_type");
                    if (Helpers.isTrue(Helpers.isEqual(payoffType, "Linear")))
                    {
                        subType = "linear";
                    } else if (Helpers.isTrue(Helpers.isEqual(payoffType, "Inverse")))
                    {
                        subType = "inverse";
                    }
                }
                Object isSpot = (Helpers.isEqual(type, "spot"));
                Object settle = ((Helpers.isTrue(settleId))) ? this.safeCurrencyCode(settleId) : null;
    final Object finalSymbol = symbol;
                final Object finalBase = base;
                final Object finalSettleId = settleId;
                final Object finalType = type;
                final Object finalSubType = subType;
                            ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                    put( "id", BitstampCore.this.safeString(market, "market_symbol") );
                    put( "symbol", finalSymbol );
                    put( "base", finalBase );
                    put( "quote", quote );
                    put( "settle", settle );
                    put( "baseId", baseId );
                    put( "quoteId", quoteId );
                    put( "settleId", finalSettleId );
                    put( "type", finalType );
                    put( "subType", finalSubType );
                    put( "spot", isSpot );
                    put( "margin", false );
                    put( "future", false );
                    put( "swap", !Helpers.isTrue(isSpot) );
                    put( "option", false );
                    put( "active", (Helpers.isEqual(BitstampCore.this.safeString(market, "trading"), "Enabled")) );
                    put( "contract", !Helpers.isTrue(isSpot) );
                    put( "linear", ((Helpers.isTrue(isSpot))) ? null : true );
                    put( "inverse", ((Helpers.isTrue(isSpot))) ? null : false );
                    put( "contractSize", null );
                    put( "expiry", null );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", BitstampCore.this.parseNumber(BitstampCore.this.parsePrecision(BitstampCore.this.safeString(market, "base_decimals"))) );
                        put( "price", BitstampCore.this.parseNumber(BitstampCore.this.parsePrecision(BitstampCore.this.safeString(market, "counter_decimals"))) );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", BitstampCore.this.safeNumber(market, "minimum_order_amount") );
                            put( "max", BitstampCore.this.safeNumber(market, "maximum_order_amount") );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", BitstampCore.this.safeNumber(market, "minimum_order_value") );
                            put( "max", BitstampCore.this.safeNumber(market, "maximum_order_value") );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", market );
                }});
            }
            return result;
        });

    }

    public Object constructCurrencyObject(Object id, Object code, Object name, Object precision, Object minCost, Object originalPayload)
    {
        Object currencyType = "crypto";
        Object description = this.describe();
        if (Helpers.isTrue(this.isFiat(code)))
        {
            currencyType = "fiat";
        }
        Object tickSize = this.parseNumber(this.parsePrecision(this.numberToString(precision)));
        final Object finalCurrencyType = currencyType;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "code", code );
            put( "info", originalPayload );
            put( "type", finalCurrencyType );
            put( "name", name );
            put( "active", true );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", BitstampCore.this.safeNumber(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(description, "fees"), "funding"), "withdraw"), code) );
            put( "precision", tickSize );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", tickSize );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", tickSize );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", minCost );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
    }

    public java.util.concurrent.CompletableFuture<Object> fetchMarketsFromCache(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // this method is now redundant
            // currencies are now fetched before markets
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object options = this.safeValue(this.options, "fetchMarkets", new java.util.HashMap<String, Object>() {{}});
            Object timestamp = this.safeInteger(options, "timestamp");
            Object expires = this.safeInteger(options, "expires", 1000);
            Object now = this.milliseconds();
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(timestamp, null))) || Helpers.isTrue((Helpers.isGreaterThan((Helpers.subtract(now, timestamp)), expires)))))
            {
                Object response = (this.publicGetMarkets(parameters)).join();
                //
                //    [
                //        {
                //            "name": "BTC/USD",
                //            "market_symbol": "btcusd",
                //            "base_currency": "BTC",
                //            "base_decimals": 8,
                //            "counter_currency": "USD",
                //            "counter_decimals": 0,
                //            "minimum_order_value": "10",
                //            "trading": "Enabled",
                //            "instant_order_counter_decimals": 2,
                //            "instant_and_market_orders": "Enabled",
                //            "description": "Bitcoin / U.S. dollar",
                //            "market_type": "SPOT"
                //        },
                //
                final Object finalNow = now;
                Helpers.addElementToObject(this.options, "fetchMarkets", this.extend(options, new java.util.HashMap<String, Object>() {{
        put( "response", response );
        put( "timestamp", finalNow );
    }}));
            }
            return this.safeValue(Helpers.GetValue(this.options, "fetchMarkets"), "response");
        });

    }

    /**
     * @method
     * @name bitstamp#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://www.bitstamp.net/api/#tag/Market-info/operation/GetTradingPairsInfo
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.fetchMarketsFromCache(parameters)).join();
            //
            //     [
            //         {
            //             "trading": "Enabled",
            //             "base_decimals": 8,
            //             "url_symbol": "btcusd",
            //             "name": "BTC/USD",
            //             "instant_and_market_orders": "Enabled",
            //             "minimum_order": "20.0 USD",
            //             "counter_decimals": 2,
            //             "description": "Bitcoin / U.S. dollar"
            //         },
            //     ]
            //
            Helpers.addElementToObject(this.options, "_temp_currencies_result", new java.util.HashMap<String, Object>() {{}});
            Object result = this.parseCurrencies(response);
            Object finalResult = this.deepExtend(result, Helpers.GetValue(this.options, "_temp_currencies_result"));
            ((java.util.Map<String,Object>)this.options).remove((String)"_temp_currencies_result");
            return finalResult;
        });

    }

    public Object parseCurrency(Object rawCurrency)
    {
        Object market = rawCurrency;
        Object existing = this.safeDict(this.options, "_temp_currencies_result", new java.util.HashMap<String, Object>() {{}});
        var baseIdquoteIdVariable = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeString(market, "base_currency"), this.safeString(market, "counter_currency")));
        var baseId = ((java.util.List<Object>) baseIdquoteIdVariable).get(0);
        var quoteId = ((java.util.List<Object>) baseIdquoteIdVariable).get(1);
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object description = this.safeString(market, "description");
        var baseDescriptionquoteDescriptionVariable = Helpers.split(description, " / ");
        var baseDescription = ((java.util.List<Object>) baseDescriptionquoteDescriptionVariable).get(0);
        var quoteDescription = ((java.util.List<Object>) baseDescriptionquoteDescriptionVariable).get(1);
        Object minimumOrder = this.safeString(market, "minimum_order_value");
        Object parts = Helpers.split(minimumOrder, " ");
        Object cost = Helpers.GetValue(parts, 0);
        if (!Helpers.isTrue((Helpers.inOp(existing, base))))
        {
            Object baseDecimals = this.safeInteger(market, "base_decimals");
            Helpers.addElementToObject(Helpers.GetValue(this.options, "_temp_currencies_result"), base, this.constructCurrencyObject(baseId, base, baseDescription, baseDecimals, null, market));
        }
        if (!Helpers.isTrue((Helpers.inOp(existing, quote))))
        {
            Object counterDecimals = this.safeInteger(market, "counter_decimals");
            Helpers.addElementToObject(Helpers.GetValue(this.options, "_temp_currencies_result"), quote, this.constructCurrencyObject(quoteId, quote, quoteDescription, counterDecimals, this.parseNumber(cost), market));
        }
        return Helpers.GetValue(Helpers.GetValue(this.options, "_temp_currencies_result"), quote);
    }

    /**
     * @method
     * @name bitstamp#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://www.bitstamp.net/api/#tag/Order-book/operation/GetOrderBook
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.publicGetOrderBookPair(this.extend(request, parameters))).join();
            //
            //     {
            //         "timestamp": "1583652948",
            //         "microtimestamp": "1583652948955826",
            //         "bids": [
            //             [ "8750.00", "1.33685271" ],
            //             [ "8749.39", "0.07700000" ],
            //             [ "8746.98", "0.07400000" ],
            //         ]
            //         "asks": [
            //             [ "8754.10", "1.51995636" ],
            //             [ "8754.71", "1.40000000" ],
            //             [ "8754.72", "2.50000000" ],
            //         ]
            //     }
            //
            Object microtimestamp = this.safeInteger(response, "microtimestamp");
            Object timestamp = this.parseToInt(Helpers.divide(microtimestamp, 1000));
            Object orderbook = this.parseOrderBook(response, Helpers.GetValue(market, "symbol"), timestamp);
            Helpers.addElementToObject(orderbook, "nonce", microtimestamp);
            return orderbook;
        });

    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // {
        //     "timestamp": "1686068944",
        //     "high": "26252",
        //     "last": "26216",
        //     "bid": "26208",
        //     "vwap": "25681",
        //     "volume": "3563.13819902",
        //     "low": "25350",
        //     "ask": "26211",
        //     "open": "25730",
        //     "open_24": "25895",
        //     "percent_change_24": "1.24",
        //     "pair": "BTC/USD"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "pair");
        Object symbol = this.safeSymbol(marketId, market);
        Object timestamp = this.safeTimestamp(ticker, "timestamp");
        Object vwap = this.safeString(ticker, "vwap");
        Object baseVolume = this.safeString(ticker, "volume");
        Object quoteVolume = Precise.stringMul(baseVolume, vwap);
        Object last = this.safeString(ticker, "last");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitstampCore.this.iso8601(timestamp) );
            put( "high", BitstampCore.this.safeString(ticker, "high") );
            put( "low", BitstampCore.this.safeString(ticker, "low") );
            put( "bid", BitstampCore.this.safeString(ticker, "bid") );
            put( "bidVolume", null );
            put( "ask", BitstampCore.this.safeString(ticker, "ask") );
            put( "askVolume", null );
            put( "vwap", vwap );
            put( "open", BitstampCore.this.safeString(ticker, "open") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

