    public Object parseTradingFee(Object fee, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(fee, "market");
        Object fees = this.safeDict(fee, "fees", new java.util.HashMap<String, Object>() {{}});
        return new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "symbol", BitstampCore.this.safeSymbol(marketId, market) );
            put( "maker", BitstampCore.this.safeNumber(fees, "maker") );
            put( "taker", BitstampCore.this.safeNumber(fees, "taker") );
            put( "percentage", null );
            put( "tierBased", null );
        }};
    }

    public Object parseTradingFees(Object fees)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fees );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(fees)); i++)
        {
            Object fee = this.parseTradingFee(Helpers.GetValue(fees, i));
            Object symbol = Helpers.GetValue(fee, "symbol");
            Helpers.addElementToObject(result, symbol, fee);
        }
        return result;
    }

