    public Object parseTransactionFees(Object response, Object... optionalArgs)
    {
        Object codes = Helpers.getArg(optionalArgs, 0, null);
        Object result = new java.util.HashMap<String, Object>() {{}};
        Object currencies = this.indexBy(response, "currency");
        Object ids = Helpers.objectKeys(currencies);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
        {
            Object id = Helpers.GetValue(ids, i);
            Object fees = this.safeValue(response, i, new java.util.HashMap<String, Object>() {{}});
            Object code = this.safeCurrencyCode(id);
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(codes, null))) && !Helpers.isTrue(this.inArray(code, codes))))
            {
                continue;
            }
            Helpers.addElementToObject(result, code, new java.util.HashMap<String, Object>() {{
    put( "withdraw_fee", BitstampCore.this.safeNumber(fees, "fee") );
    put( "deposit", new java.util.HashMap<String, Object>() {{}} );
    put( "info", BitstampCore.this.safeDict(currencies, id) );
}});
        }
        return result;
    }

    /**
     * @method
     * @name bitstamp#fetchDepositWithdrawFees
     * @description fetch deposit and withdraw fees
     * @see https://www.bitstamp.net/api/#tag/Fees/operation/GetAllWithdrawalFees
     * @param {string[]|undefined} codes list of unified currency codes
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositWithdrawFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object codes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.privatePostFeesWithdrawal(parameters)).join();
            //
            //     [
            //         {
            //             "currency": "btc",
            //             "fee": "0.00015000",
            //             "network": "bitcoin"
            //         }
            //         ...
            //     ]
            //
            Object responseByCurrencyId = this.groupBy(response, "currency");
            return this.parseDepositWithdrawFees(responseByCurrencyId, codes);
        });

    }

    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object result = this.depositWithdrawFee(fee);
        Object code = this.safeString(currency, "code");
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(fee)); j++)
        {
            Object networkEntry = Helpers.GetValue(fee, j);
            Object networkId = this.safeString(networkEntry, "network");
            Object networkCode = this.networkIdToCode(networkId, code);
            Object withdrawFee = this.safeNumber(networkEntry, "fee");
            Helpers.addElementToObject(result, "withdraw", new java.util.HashMap<String, Object>() {{
    put( "fee", withdrawFee );
    put( "percentage", null );
}});
            Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", withdrawFee );
        put( "percentage", null );
    }} );
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
}});
        }
        return result;
    }

    /**
     * @method
     * @name bitstamp#createOrder
     * @description create a trade order
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenInstantBuyOrder
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenMarketBuyOrder
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenLimitBuyOrder
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenInstantSellOrder
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenMarketSellOrder
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/OpenLimitSellOrder
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
                put( "amount", BitstampCore.this.amountToPrecision(symbol, amount) );
            }};
            Object clientOrderId = this.safeString2(parameters, "client_order_id", "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "client_order_id", clientOrderId);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId")));
            }
            Object response = null;
            Object capitalizedSide = this.capitalize(side);
            if (Helpers.isTrue(Helpers.isEqual(type, "market")))
            {
                if (Helpers.isTrue(Helpers.isEqual(capitalizedSide, "Buy")))
                {
                    response = (this.privatePostBuyMarketPair(this.extend(request, parameters))).join();
                } else
                {
                    response = (this.privatePostSellMarketPair(this.extend(request, parameters))).join();
                }
            } else if (Helpers.isTrue(Helpers.isEqual(type, "instant")))
            {
                if (Helpers.isTrue(Helpers.isEqual(capitalizedSide, "Buy")))
                {
                    response = (this.privatePostBuyInstantPair(this.extend(request, parameters))).join();
                } else
                {
                    response = (this.privatePostSellInstantPair(this.extend(request, parameters))).join();
                }
            } else
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                if (Helpers.isTrue(Helpers.isEqual(capitalizedSide, "Buy")))
                {
                    response = (this.privatePostBuyPair(this.extend(request, parameters))).join();
                } else
                {
                    response = (this.privatePostSellPair(this.extend(request, parameters))).join();
                }
            }
            Object order = this.parseOrder(response, market);
            Helpers.addElementToObject(order, "type", type);
            return order;
        });

    }

    /**
     * @method
     * @name bitstamp#editOrder
     * @description edit a trade order
     * @see https://www.bitstamp.net/api/#tag/Orders/operation/ReplaceOrder
     * @param {string} id order id
     * @param {string} [symbol] unified symbol of the market to create an order in
     * @param {string} [type] 'market', 'limit' or 'stop_limit'
     * @param {string} [side] 'buy' or 'sell'
     * @param {float} [amount] how much of the currency you want to trade in units of the base currency
     * @param {float} [price] the price for the order, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.triggerPrice] the price to trigger a stop order
     * @param {string} [params.timeInForce] for crypto trading either 'gtc' or 'ioc' can be used
     * @param {string} [params.clientOrderId] a unique identifier for the order, automatically generated if not sent
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> editOrder(Object id, Object symbol, Object type, Object side, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object amount = Helpers.getArg(optionalArgs, 0, null);
            Object price = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "amount", BitstampCore.this.amountToPrecision(symbol, amount) );
                put( "price", BitstampCore.this.priceToPrecision(symbol, price) );
            }};
            Object clientOrderId = this.safeString2(parameters, "client_order_id", "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                Helpers.addElementToObject(request, "client_order_id", clientOrderId);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId")));
            } else
            {
                Helpers.addElementToObject(request, "id", id);
            }
            Object response = (this.privatePostReplaceOrder(this.extend(request, parameters))).join();
            Object order = this.parseOrder(response, market);
            Helpers.addElementToObject(order, "type", type);
            return order;
        });

    }

